import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.C9sp7nFj.js";const u=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1776620726000}'),n={name:"guide/faq.md"};function s(r,e,h,l,d,c){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Quick answers to the most common questions.</p><h2 id="installing" tabindex="-1">Installing <a class="header-anchor" href="#installing" aria-label="Permalink to &quot;Installing&quot;">​</a></h2><h3 id="do-i-need-the-play-store" tabindex="-1">Do I need the Play Store? <a class="header-anchor" href="#do-i-need-the-play-store" aria-label="Permalink to &quot;Do I need the Play Store?&quot;">​</a></h3><p>No. Fateh HR ships as a direct APK download. When you tap it, Android asks for a one-time permission to install from that source.</p><h3 id="is-there-an-iphone-version" tabindex="-1">Is there an iPhone version? <a class="header-anchor" href="#is-there-an-iphone-version" aria-label="Permalink to &quot;Is there an iPhone version?&quot;">​</a></h3><p>Not yet — a native iOS build is on our roadmap. In the meantime, iPhone users can use the <strong>web version</strong> at <code>hr-demo.enfonoerp.com/fatehhr</code> and add it to their home screen via Safari&#39;s share menu.</p><h3 id="how-do-i-update-to-a-new-version" tabindex="-1">How do I update to a new version? <a class="header-anchor" href="#how-do-i-update-to-a-new-version" aria-label="Permalink to &quot;How do I update to a new version?&quot;">​</a></h3><p>Your HR team shares the new APK link. Tap it → Install → you&#39;re updated. Your PIN and login stay.</p><h2 id="login-security" tabindex="-1">Login &amp; security <a class="header-anchor" href="#login-security" aria-label="Permalink to &quot;Login &amp; security&quot;">​</a></h2><h3 id="can-i-share-the-app-with-a-colleague" tabindex="-1">Can I share the app with a colleague? <a class="header-anchor" href="#can-i-share-the-app-with-a-colleague" aria-label="Permalink to &quot;Can I share the app with a colleague?&quot;">​</a></h3><p>Each person needs their <strong>own login</strong>. Sharing an account means your check-ins and payslips show up as theirs. Ask HR to set your colleague up with their own work email.</p><h3 id="does-the-app-know-my-location-all-the-time" tabindex="-1">Does the app know my location all the time? <a class="header-anchor" href="#does-the-app-know-my-location-all-the-time" aria-label="Permalink to &quot;Does the app know my location all the time?&quot;">​</a></h3><p><strong>No.</strong> Location is only captured at the moment you tap <strong>Check In</strong> or <strong>Check Out</strong>. There&#39;s no background location tracking.</p><h3 id="what-data-is-stored-on-my-phone" tabindex="-1">What data is stored on my phone? <a class="header-anchor" href="#what-data-is-stored-on-my-phone" aria-label="Permalink to &quot;What data is stored on my phone?&quot;">​</a></h3><ul><li>Your session token (not your password)</li><li>A hashed version of your PIN (so offline unlock works)</li><li>Any check-ins / leave / expense submissions you&#39;ve done offline and are queued to sync</li><li>Your last-viewed attendance data (for offline viewing)</li><li>Photos of selfies and expense receipts you haven&#39;t uploaded yet</li></ul><h3 id="can-it-see-what-i-do-on-my-phone" tabindex="-1">Can IT see what I do on my phone? <a class="header-anchor" href="#can-it-see-what-i-do-on-my-phone" aria-label="Permalink to &quot;Can IT see what I do on my phone?&quot;">​</a></h3><p>No. The Fateh HR app only sees what happens <strong>inside the app</strong>. It doesn&#39;t have access to your photos, messages, calls, or other apps.</p><h2 id="check-in" tabindex="-1">Check-in <a class="header-anchor" href="#check-in" aria-label="Permalink to &quot;Check-in&quot;">​</a></h2><h3 id="i-forgot-to-check-out-yesterday-what-happens" tabindex="-1">I forgot to check out yesterday. What happens? <a class="header-anchor" href="#i-forgot-to-check-out-yesterday-what-happens" aria-label="Permalink to &quot;I forgot to check out yesterday. What happens?&quot;">​</a></h3><p>The app auto-closes the open pair at midnight. The day will still show as <strong>Present</strong> but the hours will stop at 23:59. In the attendance calendar&#39;s day detail, the pair is marked <strong>&quot;auto-closed at midnight&quot;</strong> so HR knows.</p><h3 id="i-checked-in-at-the-wrong-location-by-mistake-can-i-delete-it" tabindex="-1">I checked in at the wrong location by mistake. Can I delete it? <a class="header-anchor" href="#i-checked-in-at-the-wrong-location-by-mistake-can-i-delete-it" aria-label="Permalink to &quot;I checked in at the wrong location by mistake. Can I delete it?&quot;">​</a></h3><p>Not from the app. Ask HR — they can delete or amend the Employee Checkin record from the Desk.</p><h3 id="can-i-check-in-from-anywhere-or-only-at-my-work-location" tabindex="-1">Can I check in from anywhere, or only at my work location? <a class="header-anchor" href="#can-i-check-in-from-anywhere-or-only-at-my-work-location" aria-label="Permalink to &quot;Can I check in from anywhere, or only at my work location?&quot;">​</a></h3><p>Depends on your task. If your task has a <strong>geofence radius</strong>, you can check in anywhere but being outside the radius is flagged for manager review. If no geofence is set, anywhere goes.</p><h2 id="offline" tabindex="-1">Offline <a class="header-anchor" href="#offline" aria-label="Permalink to &quot;Offline&quot;">​</a></h2><h3 id="how-long-can-i-work-offline" tabindex="-1">How long can I work offline? <a class="header-anchor" href="#how-long-can-i-work-offline" aria-label="Permalink to &quot;How long can I work offline?&quot;">​</a></h3><p>Indefinitely — as long as the app has storage for queued items and photos. Typical usage is days to weeks between syncs without trouble.</p><h3 id="if-i-m-offline-for-a-week-will-i-lose-my-check-ins" tabindex="-1">If I&#39;m offline for a week, will I lose my check-ins? <a class="header-anchor" href="#if-i-m-offline-for-a-week-will-i-lose-my-check-ins" aria-label="Permalink to &quot;If I&#39;m offline for a week, will I lose my check-ins?&quot;">​</a></h3><p>No. Every check-in is stored locally until it can be uploaded. When you get back online, they all sync automatically in the order they happened.</p><h3 id="do-offline-check-ins-record-the-right-time" tabindex="-1">Do offline check-ins record the right time? <a class="header-anchor" href="#do-offline-check-ins-record-the-right-time" aria-label="Permalink to &quot;Do offline check-ins record the right time?&quot;">​</a></h3><p>Yes. The app timestamps every action at the <strong>moment you tap</strong> the button, not when it syncs. So if you checked in at 08:00 and synced at 14:00, the server shows 08:00.</p><h3 id="i-uninstalled-the-app-before-my-queued-check-ins-synced-are-they-gone" tabindex="-1">I uninstalled the app before my queued check-ins synced. Are they gone? <a class="header-anchor" href="#i-uninstalled-the-app-before-my-queued-check-ins-synced-are-they-gone" aria-label="Permalink to &quot;I uninstalled the app before my queued check-ins synced. Are they gone?&quot;">​</a></h3><p>Yes, unfortunately. Offline data lives inside the app&#39;s private storage; uninstalling wipes it. Always make sure the sync bar says <strong>&quot;Synced now&quot;</strong> before uninstalling.</p><h2 id="leave-expense" tabindex="-1">Leave &amp; expense <a class="header-anchor" href="#leave-expense" aria-label="Permalink to &quot;Leave &amp; expense&quot;">​</a></h2><h3 id="i-need-to-apply-for-leave-i-already-took-can-i-backdate" tabindex="-1">I need to apply for leave I already took. Can I backdate? <a class="header-anchor" href="#i-need-to-apply-for-leave-i-already-took-can-i-backdate" aria-label="Permalink to &quot;I need to apply for leave I already took. Can I backdate?&quot;">​</a></h3><p>Yes. Just pick the past dates in the From/To fields. HR will see the submission date is different from the leave dates — normal and expected for post-facto requests.</p><h3 id="my-leave-balance-shows-0-but-hr-said-i-should-have-some" tabindex="-1">My leave balance shows 0 but HR said I should have some. <a class="header-anchor" href="#my-leave-balance-shows-0-but-hr-said-i-should-have-some" aria-label="Permalink to &quot;My leave balance shows 0 but HR said I should have some.&quot;">​</a></h3><p>HR needs to create a <strong>Leave Allocation</strong> for you on the Desk. Ask them to check <strong>HR → Leave Allocation</strong> for your employee record.</p><h3 id="can-i-file-a-claim-without-a-receipt" tabindex="-1">Can I file a claim without a receipt? <a class="header-anchor" href="#can-i-file-a-claim-without-a-receipt" aria-label="Permalink to &quot;Can I file a claim without a receipt?&quot;">​</a></h3><p>No — every line requires a receipt photo. If you&#39;ve lost a receipt, mention it to HR separately; they can record it on the Desk with appropriate notes.</p><h3 id="my-expense-claim-was-approved-for-less-than-i-claimed-why" tabindex="-1">My expense claim was approved for less than I claimed. Why? <a class="header-anchor" href="#my-expense-claim-was-approved-for-less-than-i-claimed-why" aria-label="Permalink to &quot;My expense claim was approved for less than I claimed. Why?&quot;">​</a></h3><p>Approvers can reduce the sanctioned amount. Open the claim in the app, scroll to the &quot;Approved&quot; figure — it shows what was approved. Ask your approver if you need justification.</p><h2 id="payslip" tabindex="-1">Payslip <a class="header-anchor" href="#payslip" aria-label="Permalink to &quot;Payslip&quot;">​</a></h2><h3 id="the-payslip-number-looks-weird-—-sal-slip-none" tabindex="-1">The payslip number looks weird — &quot;Sal Slip/None/…&quot; <a class="header-anchor" href="#the-payslip-number-looks-weird-—-sal-slip-none" aria-label="Permalink to &quot;The payslip number looks weird — &quot;Sal Slip/None/…&quot;&quot;">​</a></h3><p>That&#39;s the default Frappe naming series; your HR can customise it. It doesn&#39;t affect the contents of the payslip.</p><h3 id="can-i-see-payslips-from-before-i-started-using-the-app" tabindex="-1">Can I see payslips from before I started using the app? <a class="header-anchor" href="#can-i-see-payslips-from-before-i-started-using-the-app" aria-label="Permalink to &quot;Can I see payslips from before I started using the app?&quot;">​</a></h3><p>If they were generated on the Frappe HR Desk, yes — they&#39;re all there. The app lists everything linked to your Employee record.</p><h3 id="my-net-pay-is-wrong" tabindex="-1">My net pay is wrong. <a class="header-anchor" href="#my-net-pay-is-wrong" aria-label="Permalink to &quot;My net pay is wrong.&quot;">​</a></h3><p>The app only <strong>displays</strong> what the Desk computes. If a figure&#39;s wrong:</p><ol><li>Note the exact discrepancy</li><li>Tell HR with the payslip name (e.g. <code>Sal Slip/None/00006</code>)</li><li>HR corrects it on the Desk, and your app view updates automatically</li></ol><h2 id="app-behaviour" tabindex="-1">App behaviour <a class="header-anchor" href="#app-behaviour" aria-label="Permalink to &quot;App behaviour&quot;">​</a></h2><h3 id="why-does-the-app-auto-close-after-i-log-in-sometimes" tabindex="-1">Why does the app auto-close after I log in sometimes? <a class="header-anchor" href="#why-does-the-app-auto-close-after-i-log-in-sometimes" aria-label="Permalink to &quot;Why does the app auto-close after I log in sometimes?&quot;">​</a></h3><p>That&#39;s your <strong>session timeout</strong> (~2 hours of inactivity). Next time you open it, it&#39;ll ask for your PIN / fingerprint instead of a full login. Totally expected.</p><h3 id="why-is-the-calendar-blank-for-the-first-few-seconds" tabindex="-1">Why is the calendar blank for the first few seconds? <a class="header-anchor" href="#why-is-the-calendar-blank-for-the-first-few-seconds" aria-label="Permalink to &quot;Why is the calendar blank for the first few seconds?&quot;">​</a></h3><p>You&#39;re watching the monthly data load. The app shows a pulsing skeleton grid until the real data arrives — usually 1-3 seconds.</p><h3 id="the-app-shows-a-toast-press-back-again-to-exit-—-what-does-it-mean" tabindex="-1">The app shows a toast &quot;Press back again to exit&quot; — what does it mean? <a class="header-anchor" href="#the-app-shows-a-toast-press-back-again-to-exit-—-what-does-it-mean" aria-label="Permalink to &quot;The app shows a toast &quot;Press back again to exit&quot; — what does it mean?&quot;">​</a></h3><p>On Android, pressing the back button from the home screen triggers a double-tap-to-exit. This prevents accidental exits. Press back again within 2 seconds to actually exit.</p><h3 id="can-i-use-a-tablet" tabindex="-1">Can I use a tablet? <a class="header-anchor" href="#can-i-use-a-tablet" aria-label="Permalink to &quot;Can I use a tablet?&quot;">​</a></h3><p>Yes, the web app works well on tablets. The native APK is sized for phones but runs on tablets in phone layout.</p><h2 id="data-privacy" tabindex="-1">Data &amp; privacy <a class="header-anchor" href="#data-privacy" aria-label="Permalink to &quot;Data &amp; privacy&quot;">​</a></h2><h3 id="where-is-my-data-stored" tabindex="-1">Where is my data stored? <a class="header-anchor" href="#where-is-my-data-stored" aria-label="Permalink to &quot;Where is my data stored?&quot;">​</a></h3><ul><li><strong>Cloud:</strong> Your employer&#39;s Frappe/ERPNext server (your HR&#39;s choice of hosting).</li><li><strong>Device:</strong> Only the data needed for offline use + your session token. Everything syncs with the cloud as the source of truth.</li></ul><h3 id="what-happens-if-my-phone-is-stolen" tabindex="-1">What happens if my phone is stolen? <a class="header-anchor" href="#what-happens-if-my-phone-is-stolen" aria-label="Permalink to &quot;What happens if my phone is stolen?&quot;">​</a></h3><ul><li>Your session is protected by PIN / biometric. The thief can&#39;t open the app without it.</li><li>Ask HR to <strong>reset your API credentials</strong> on the Desk — this invalidates the stolen phone&#39;s session.</li><li>Set a new PIN after you get a new phone.</li></ul><h3 id="does-the-app-use-mobile-data" tabindex="-1">Does the app use mobile data? <a class="header-anchor" href="#does-the-app-use-mobile-data" aria-label="Permalink to &quot;Does the app use mobile data?&quot;">​</a></h3><ul><li>When online, yes — for sync, map tiles, selfie uploads.</li><li>For light users, typical usage is under 20 MB/month.</li><li>Heavy selfie / photo use can push that to 50–100 MB/month.</li><li>OpenStreetMap tiles on the check-in map are cached after first load, so repeat visits to the same area reuse cached tiles.</li></ul><h2 id="couldn-t-find-your-answer" tabindex="-1">Couldn&#39;t find your answer? <a class="header-anchor" href="#couldn-t-find-your-answer" aria-label="Permalink to &quot;Couldn&#39;t find your answer?&quot;">​</a></h2><p>Visit the full <strong><a href="/guide/getting-started">User Guide</a></strong> or contact your HR team.</p>',69)])])}const f=a(n,[["render",s]]);export{u as __pageData,f as default};
